"use client";

import { Trash2, Copy, Check, DollarSign, Clock, Hash } from "lucide-react";
import { useState } from "react";
import { CATEGORIES, formatMulra } from "@/data/crimes";
import type { CrimeCount } from "@/types";

interface Props {
  counts: CrimeCount;
  totalMulta: number;
  totalMeses: number;
  onClear: () => void;
}

export default function SummaryPanel({ counts, totalMulta, totalMeses, onClear }: Props) {
  const [copied, setCopied] = useState(false);

  const selectedCrimes = CATEGORIES.flatMap((cat) =>
    cat.crimes
      .filter((c) => (counts[c.id] ?? 0) > 0)
      .map((c) => ({ ...c, count: counts[c.id] }))
  );

  const totalCharges = selectedCrimes.reduce((sum, c) => sum + c.count, 0);

  const handleCopy = () => {
    if (selectedCrimes.length === 0) return;
    const lines = [
      "📋 BOLETIM DE OCORRÊNCIA — FRONTEIRA RP",
      "═".repeat(40),
      "",
      "CRIMES COMETIDOS:",
      ...selectedCrimes.map(
        (c) =>
          `  • ${c.name}${c.count > 1 ? ` (×${c.count})` : ""} — ${formatMulra(c.multa * c.count)} / ${c.meses * c.count} meses`
      ),
      "",
      "─".repeat(40),
      `💰 MULTA TOTAL: ${formatMulra(totalMulta)}`,
      `⏳ PRISÃO TOTAL: ${totalMeses} meses`,
    ];
    navigator.clipboard.writeText(lines.join("\n")).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  return (
    <div className="fixed bottom-0 left-0 right-0 z-50 border-t border-slate-700/60 bg-slate-950/95 backdrop-blur-md shadow-2xl">
      <div className="max-w-7xl mx-auto px-4 py-3">
        <div className="flex flex-col sm:flex-row items-start sm:items-center gap-3">

          <div className="flex items-center gap-4 flex-1 flex-wrap">
            <Stat
              icon={<Hash size={14} />}
              label="Infrações"
              value={String(totalCharges)}
              highlight={totalCharges > 0}
              color="blue"
            />
            <div className="h-6 w-px bg-slate-700 hidden sm:block" />
            <Stat
              icon={<DollarSign size={14} />}
              label="Multa Total"
              value={totalMulta > 0 ? formatMulra(totalMulta) : "R$ 0"}
              highlight={totalMulta > 0}
              color="emerald"
            />
            <div className="h-6 w-px bg-slate-700 hidden sm:block" />
            <Stat
              icon={<Clock size={14} />}
              label="Prisão"
              value={`${totalMeses} meses`}
              highlight={totalMeses > 0}
              color="orange"
            />
          </div>

          <div className="flex gap-2 shrink-0">
            <button
              onClick={handleCopy}
              disabled={selectedCrimes.length === 0}
              className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-semibold bg-slate-800 hover:bg-slate-700 text-slate-300 disabled:opacity-40 disabled:cursor-not-allowed transition-all"
            >
              {copied ? <Check size={13} className="text-green-400" /> : <Copy size={13} />}
              {copied ? "Copiado!" : "Copiar"}
            </button>
            <button
              onClick={onClear}
              disabled={selectedCrimes.length === 0}
              className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-semibold bg-red-950 hover:bg-red-900 text-red-400 disabled:opacity-40 disabled:cursor-not-allowed transition-all"
            >
              <Trash2 size={13} />
              Limpar
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

function Stat({
  icon,
  label,
  value,
  highlight,
  color,
}: {
  icon: React.ReactNode;
  label: string;
  value: string;
  highlight: boolean;
  color: "blue" | "emerald" | "orange";
}) {
  const colors = {
    blue: highlight ? "text-blue-400" : "text-slate-500",
    emerald: highlight ? "text-emerald-400" : "text-slate-500",
    orange: highlight ? "text-orange-400" : "text-slate-500",
  };
  return (
    <div className="flex items-center gap-2">
      <span className={`${colors[color]} transition-colors`}>{icon}</span>
      <div>
        <p className="text-[10px] text-slate-500 uppercase tracking-wider">{label}</p>
        <p className={`text-sm font-bold font-mono transition-colors ${colors[color]}`}>{value}</p>
      </div>
    </div>
  );
}
